#define BIN_COUNT 1024 
#define HISTOGRAM_SIZE (BIN_COUNT * sizeof(unsigned int))

#define WARP_LOG_SIZE 5
#define WARP_N 3

#ifdef HISTO_WG_SIZE_0
#define THREAD_N HISTO_WG_SIZE_0
#else
#define THREAD_N (WARP_N << WARP_LOG_SIZE)
#endif

#define BLOCK_MEMORY (WARP_N * BIN_COUNT)

inline void addData1024(volatile __local unsigned int *s_WarpHist, unsigned int data, unsigned int threadTag){
    unsigned int count;
    do{
        count = s_WarpHist[data] & 0x07FFFFFFU;
        count = threadTag | (count + 1);
        s_WarpHist[data] = count;
    }while(s_WarpHist[data] != count);
}

__kernel void histogram1024Kernel(__global unsigned int *d_Result, __global float *d_Data, float minimum, float maximum, int dataN){

    const int globalTid = get_global_id(0);
    const int numThreads = get_global_size(0);

    const unsigned int threadTag = get_local_id(0) << (32 - WARP_LOG_SIZE);

    volatile __local unsigned int s_Hist[BLOCK_MEMORY];

    const int warpBase = (get_local_id(0) >> WARP_LOG_SIZE) * BIN_COUNT;

    for(int pos = get_local_id(0); pos < BLOCK_MEMORY; pos += get_local_size(0))
       s_Hist[pos] = 0;

    barrier(CLK_LOCAL_MEM_FENCE);

    for(int pos = globalTid; pos < dataN; pos += numThreads){
        unsigned int data4 = (unsigned int)(((d_Data[pos] - minimum)/(maximum - minimum)) * BIN_COUNT);
        addData1024(s_Hist + warpBase, data4 & 0x3FFU, threadTag);
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for(int pos = get_local_id(0); pos < BIN_COUNT; pos += get_local_size(0)){
        unsigned int sum = 0;

        for(int base = 0; base < BLOCK_MEMORY; base += BIN_COUNT)
            sum += s_Hist[base + pos] & 0x07FFFFFFU;
        atomic_add(&d_Result[pos], sum);
    }
}
